#!/usr/bin/env node
/**
 * runner/sprint/db.js — SQLite database for sprint planning & tracking
 *
 * Schema:
 *   plans           — the 30-day plan (1 active at a time)
 *   sprints         — weekly sprints within a plan
 *   tasks           — actionable tasks within each sprint
 *   accomplishments — what Sebastian actually did (linked to tasks or standalone)
 *   daily_logs      — daily focus / standup generated by tracker
 *
 * All timestamps are ISO strings. IDs are auto-incremented.
 * Uses WAL mode for safe single-writer access.
 */

"use strict";

const Database = require("better-sqlite3");
const path     = require("path");
const fs       = require("fs");

const DB_PATH = path.resolve(__dirname, "../../state/sprints.db");

// Ensure state/ directory exists
const stateDir = path.dirname(DB_PATH);
if (!fs.existsSync(stateDir)) fs.mkdirSync(stateDir, { recursive: true });

const db = new Database(DB_PATH);
db.pragma("journal_mode = WAL");
db.pragma("synchronous = NORMAL");
db.pragma("foreign_keys = ON");

// ── Schema ────────────────────────────────────────────────────────────────────
db.exec(`
  CREATE TABLE IF NOT EXISTS plans (
    id              INTEGER PRIMARY KEY AUTOINCREMENT,
    plan_id         TEXT    NOT NULL UNIQUE,
    title           TEXT    NOT NULL,
    status          TEXT    NOT NULL DEFAULT 'active',
    compulsion      TEXT,
    brief           TEXT,
    success_30d     TEXT,
    belief_axes     TEXT,
    activated_date  TEXT    NOT NULL,
    target_end_date TEXT,
    completed_date  TEXT,
    created_at      TEXT    NOT NULL DEFAULT (datetime('now'))
  );

  CREATE TABLE IF NOT EXISTS sprints (
    id          INTEGER PRIMARY KEY AUTOINCREMENT,
    plan_id     TEXT    NOT NULL REFERENCES plans(plan_id),
    week        INTEGER NOT NULL,
    goal        TEXT    NOT NULL,
    status      TEXT    NOT NULL DEFAULT 'not_started',
    start_date  TEXT,
    end_date    TEXT,
    retro       TEXT,
    created_at  TEXT    NOT NULL DEFAULT (datetime('now')),
    UNIQUE(plan_id, week)
  );

  CREATE TABLE IF NOT EXISTS tasks (
    id              INTEGER PRIMARY KEY AUTOINCREMENT,
    sprint_id       INTEGER NOT NULL REFERENCES sprints(id),
    title           TEXT    NOT NULL,
    description     TEXT,
    task_type       TEXT    NOT NULL DEFAULT 'action',
    status          TEXT    NOT NULL DEFAULT 'todo',
    priority        INTEGER NOT NULL DEFAULT 2,
    estimated_hours REAL,
    actual_hours    REAL,
    output_ref      TEXT,
    completed_date  TEXT,
    created_at      TEXT    NOT NULL DEFAULT (datetime('now'))
  );

  CREATE INDEX IF NOT EXISTS idx_tasks_sprint  ON tasks(sprint_id);
  CREATE INDEX IF NOT EXISTS idx_tasks_status  ON tasks(status);

  CREATE TABLE IF NOT EXISTS accomplishments (
    id          INTEGER PRIMARY KEY AUTOINCREMENT,
    plan_id     TEXT    NOT NULL REFERENCES plans(plan_id),
    task_id     INTEGER REFERENCES tasks(id),
    date        TEXT    NOT NULL,
    description TEXT    NOT NULL,
    evidence    TEXT,
    impact      TEXT,
    created_at  TEXT    NOT NULL DEFAULT (datetime('now'))
  );

  CREATE INDEX IF NOT EXISTS idx_acc_plan ON accomplishments(plan_id);
  CREATE INDEX IF NOT EXISTS idx_acc_date ON accomplishments(date DESC);

  CREATE TABLE IF NOT EXISTS daily_logs (
    id           INTEGER PRIMARY KEY AUTOINCREMENT,
    plan_id      TEXT    NOT NULL REFERENCES plans(plan_id),
    date         TEXT    NOT NULL,
    focus        TEXT,
    active_tasks TEXT,
    blockers     TEXT,
    notes        TEXT,
    created_at   TEXT    NOT NULL DEFAULT (datetime('now')),
    UNIQUE(plan_id, date)
  );
`);

// ── Plan helpers ──────────────────────────────────────────────────────────────

function getActivePlan() {
  return db.prepare("SELECT * FROM plans WHERE status = 'active' LIMIT 1").get() || null;
}

function upsertPlan({ plan_id, title, compulsion, brief, success_30d, belief_axes, activated_date }) {
  const target_end_date = addDays(activated_date, 30);
  const existing = db.prepare("SELECT id FROM plans WHERE plan_id = ?").get(plan_id);
  if (existing) {
    db.prepare(`
      UPDATE plans SET title = ?, compulsion = ?, brief = ?, success_30d = ?,
        belief_axes = ?, activated_date = ?, target_end_date = ?, status = 'active'
      WHERE plan_id = ?
    `).run(title, compulsion, brief, success_30d, JSON.stringify(belief_axes), activated_date, target_end_date, plan_id);
  } else {
    db.prepare(`
      INSERT INTO plans (plan_id, title, compulsion, brief, success_30d, belief_axes, activated_date, target_end_date)
      VALUES (?, ?, ?, ?, ?, ?, ?, ?)
    `).run(plan_id, title, compulsion, brief, success_30d, JSON.stringify(belief_axes), activated_date, target_end_date);
  }
  return db.prepare("SELECT * FROM plans WHERE plan_id = ?").get(plan_id);
}

function completePlan(plan_id, date) {
  db.prepare("UPDATE plans SET status = 'completed', completed_date = ? WHERE plan_id = ?").run(date, plan_id);
}

// ── Sprint helpers ────────────────────────────────────────────────────────────

function getSprints(plan_id) {
  return db.prepare("SELECT * FROM sprints WHERE plan_id = ? ORDER BY week").all(plan_id);
}

function getCurrentSprint(plan_id) {
  return db.prepare(
    "SELECT * FROM sprints WHERE plan_id = ? AND status = 'active' ORDER BY week LIMIT 1"
  ).get(plan_id) || null;
}

function upsertSprint({ plan_id, week, goal, start_date, end_date }) {
  const existing = db.prepare("SELECT id FROM sprints WHERE plan_id = ? AND week = ?").get(plan_id, week);
  if (existing) {
    db.prepare("UPDATE sprints SET goal = ?, start_date = ?, end_date = ? WHERE id = ?")
      .run(goal, start_date || null, end_date || null, existing.id);
    return existing.id;
  }
  const res = db.prepare(
    "INSERT INTO sprints (plan_id, week, goal, start_date, end_date) VALUES (?, ?, ?, ?, ?)"
  ).run(plan_id, week, goal, start_date || null, end_date || null);
  return res.lastInsertRowid;
}

function activateSprint(sprint_id, start_date) {
  db.prepare("UPDATE sprints SET status = 'active', start_date = ? WHERE id = ?")
    .run(start_date, sprint_id);
}

function completeSprint(sprint_id, retro) {
  db.prepare("UPDATE sprints SET status = 'completed', retro = ? WHERE id = ?")
    .run(retro || null, sprint_id);
}

// ── Task helpers ──────────────────────────────────────────────────────────────

function getTasks(sprint_id) {
  return db.prepare("SELECT * FROM tasks WHERE sprint_id = ? ORDER BY priority, id").all(sprint_id);
}

function getTasksByStatus(sprint_id, status) {
  return db.prepare("SELECT * FROM tasks WHERE sprint_id = ? AND status = ? ORDER BY priority, id")
    .all(sprint_id, status);
}

function addTask({ sprint_id, title, description, task_type, priority, estimated_hours }) {
  const res = db.prepare(`
    INSERT INTO tasks (sprint_id, title, description, task_type, priority, estimated_hours)
    VALUES (?, ?, ?, ?, ?, ?)
  `).run(sprint_id, title, description || null, task_type || "action", priority || 2, estimated_hours || null);
  return res.lastInsertRowid;
}

function updateTaskStatus(task_id, status, output_ref) {
  const completed_date = status === "done" ? new Date().toISOString().slice(0, 10) : null;
  db.prepare(
    "UPDATE tasks SET status = ?, output_ref = COALESCE(?, output_ref), completed_date = COALESCE(?, completed_date) WHERE id = ?"
  ).run(status, output_ref || null, completed_date, task_id);
}

function bulkInsertTasks(sprint_id, tasks) {
  const insert = db.prepare(`
    INSERT INTO tasks (sprint_id, title, description, task_type, priority, estimated_hours)
    VALUES (?, ?, ?, ?, ?, ?)
  `);
  const run = db.transaction((taskList) => {
    for (const t of taskList) {
      insert.run(sprint_id, t.title, t.description || null, t.task_type || "action", t.priority || 2, t.estimated_hours || null);
    }
  });
  run(tasks);
}

// ── Accomplishment helpers ────────────────────────────────────────────────────

function addAccomplishment({ plan_id, task_id, date, description, evidence, impact }) {
  db.prepare(`
    INSERT INTO accomplishments (plan_id, task_id, date, description, evidence, impact)
    VALUES (?, ?, ?, ?, ?, ?)
  `).run(plan_id, task_id || null, date, description, evidence || null, impact || null);
}

function getAccomplishments(plan_id, since_date) {
  if (since_date) {
    return db.prepare("SELECT * FROM accomplishments WHERE plan_id = ? AND date >= ? ORDER BY date DESC")
      .all(plan_id, since_date);
  }
  return db.prepare("SELECT * FROM accomplishments WHERE plan_id = ? ORDER BY date DESC").all(plan_id);
}

// ── Daily log helpers ─────────────────────────────────────────────────────────

function upsertDailyLog({ plan_id, date, focus, active_tasks, blockers, notes }) {
  db.prepare(`
    INSERT INTO daily_logs (plan_id, date, focus, active_tasks, blockers, notes)
    VALUES (?, ?, ?, ?, ?, ?)
    ON CONFLICT(plan_id, date) DO UPDATE SET
      focus = excluded.focus, active_tasks = excluded.active_tasks,
      blockers = excluded.blockers, notes = excluded.notes
  `).run(plan_id, date, focus || null, active_tasks || null, blockers || null, notes || null);
}

function getDailyLog(plan_id, date) {
  return db.prepare("SELECT * FROM daily_logs WHERE plan_id = ? AND date = ?").get(plan_id, date) || null;
}

function getRecentDailyLogs(plan_id, limit) {
  return db.prepare("SELECT * FROM daily_logs WHERE plan_id = ? ORDER BY date DESC LIMIT ?")
    .all(plan_id, limit || 7);
}

// ── Summary / context helpers ─────────────────────────────────────────────────

function getSprintSummary(plan_id) {
  const plan = db.prepare("SELECT * FROM plans WHERE plan_id = ?").get(plan_id);
  if (!plan) return null;

  const sprints = getSprints(plan_id);
  const current = getCurrentSprint(plan_id);
  const result = {
    plan_title: plan.title,
    plan_status: plan.status,
    activated: plan.activated_date,
    target_end: plan.target_end_date,
    total_sprints: sprints.length,
    current_week: current ? current.week : null,
    current_goal: current ? current.goal : null,
    sprints: sprints.map(s => {
      const tasks = getTasks(s.id);
      const done = tasks.filter(t => t.status === "done").length;
      return {
        week: s.week,
        goal: s.goal,
        status: s.status,
        tasks_total: tasks.length,
        tasks_done: done,
      };
    }),
  };

  if (current) {
    result.current_tasks = getTasks(current.id).map(t => ({
      id: t.id,
      title: t.title,
      status: t.status,
      type: t.task_type,
    }));
  }

  return result;
}

/**
 * Build a concise context string for injection into the tweet agent prompt.
 * Returns a multi-line text block.
 */
function buildPromptContext(plan_id) {
  const summary = getSprintSummary(plan_id);
  if (!summary) return "(no active sprint)";

  const lines = [];
  lines.push(`PLAN: ${summary.plan_title} (${summary.plan_status})`);
  lines.push(`Timeline: ${summary.activated} → ${summary.target_end}`);

  if (summary.current_week) {
    lines.push(`Current: Week ${summary.current_week} — ${summary.current_goal}`);
    if (summary.current_tasks?.length) {
      lines.push("Tasks:");
      for (const t of summary.current_tasks) {
        const icon = t.status === "done" ? "✓" : t.status === "in_progress" ? "▸" : "○";
        lines.push(`  ${icon} [${t.type}] ${t.title}`);
      }
    }
  }

  // Show sprint progress overview
  for (const s of summary.sprints) {
    if (s.week === summary.current_week) continue;
    const icon = s.status === "completed" ? "✓" : s.status === "active" ? "▸" : "○";
    lines.push(`${icon} Week ${s.week}: ${s.goal} (${s.tasks_done}/${s.tasks_total} done)`);
  }

  return lines.join("\n");
}

// ── Utility ───────────────────────────────────────────────────────────────────

function addDays(dateStr, n) {
  const d = new Date(dateStr);
  d.setDate(d.getDate() + n);
  return d.toISOString().slice(0, 10);
}

function close() {
  db.close();
}

module.exports = {
  db,
  // Plan
  getActivePlan, upsertPlan, completePlan,
  // Sprint
  getSprints, getCurrentSprint, upsertSprint, activateSprint, completeSprint,
  // Task
  getTasks, getTasksByStatus, addTask, updateTaskStatus, bulkInsertTasks,
  // Accomplishment
  addAccomplishment, getAccomplishments,
  // Daily log
  upsertDailyLog, getDailyLog, getRecentDailyLogs,
  // Summary
  getSprintSummary, buildPromptContext,
  // Util
  addDays, close,
};
